def check_user_role(user_id):
    # Check if user exists in USERS
    if user_id not in USERS:
        return "user"

    # Check if user is admin
    if USERS[user_id]["role"] == "admin":
        return "admin"

    # Check if user is a project owner
    for project_id, project_data in PROJECTS.items():
        if project_data["owner_id"] == user_id:
            return "owner"

    # Default to regular user
    return "user"

def can_modify_project(current_user_id, project_id):
    # Check if project exists
    if project_id not in PROJECTS:
        return False

    # Get user role
    user_role = check_user_role(current_user_id)

    # Admins can modify any project
    if user_role == "admin":
        return True

    # Check if user is the owner of this specific project
    if PROJECTS[project_id]["owner_id"] == current_user_id:
        return True

    # Regular users and owners of other projects cannot modify
    return False

def manage_project_access(current_user_id, project_id, action, target_user_id):
    # Check if project exists
    if project_id not in PROJECTS:
        return False

    # Check if target user exists
    if target_user_id not in USERS:
        return False

    # Check if current user can modify the project
    if not can_modify_project(current_user_id, project_id):
        return False

    # Perform the action
    if action == "add":
        if target_user_id not in PROJECTS[project_id]["members"]:
            PROJECTS[project_id]["members"].append(target_user_id)
            return True
        return False
    elif action == "remove":
        if target_user_id in PROJECTS[project_id]["members"]:
            # Cannot remove the owner from members
            if target_user_id == PROJECTS[project_id]["owner_id"]:
                return False
            PROJECTS[project_id]["members"].remove(target_user_id)
            return True
        return False
    else:
        return False

